window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]=window.__LIBQ["the-gioi-hoan-my"]["q01"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]["map"]={"updatedAt":"2026-07-04","count":126,"nodes":[{"id":"day-nui-thuong-mang","name":"Dãy núi Thương Mãng","cn":"","capDo":"vuc","parentId":null,"blurb":"Quần thể núi non nguy nga kỳ vĩ trải ngút tầm nhìn, đầy hồng hoang mãnh thú độc trùng cực kỳ nguy hiểm.","detail":"Dãy núi Thương Mãng là quần thể núi non nguy nga kỳ vĩ trải ngút tầm nhìn, bốn bề núi cao khe lớn. Trong núi nhiều hồng hoang mãnh thú độc trùng, môi trường sinh tồn cực kỳ khốc liệt; Thạch Thôn tọa lạc nơi đây.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0001"]},{"id":"thach-thon-dia-danh","name":"Thạch Thôn","cn":"","capDo":"khac","parentId":"day-nui-thuong-mang","blurb":"Thôn làng trong dãy núi Thương Mãng, nhà ghép từ đá tảng, đầu thôn có gốc cây sét đánh.","detail":"Thôn làng nằm trong dãy núi Thương Mãng, bốn bề núi cao khe lớn, nhà ghép từ đá tảng. Trước thôn có khoảng đất trống nơi tộc nhân rèn luyện; đầu thôn có gốc cây sét đánh (liễu già) được cúng tế là Tế Linh.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0001","@c0032"]},{"id":"dai-hoang","name":"Đại Hoang","cn":"","capDo":"vuc","parentId":"day-nui-thuong-mang","blurb":"Khu vực sâu trong núi không ai sống sót đi vào; nghi đang xuất hiện dị biến thu hút chủng tộc Thái Cổ.","detail":"Đại Hoang là vùng sâu trong dãy núi Thương Mãng, không ai sống sót đi vào. Gần đây nghi xuất hiện dị biến hay sơn bảo, thu hút các chủng tộc sót lại từ Thái Cổ kéo về.","theLucLienQuan":["Chủng tộc sót lại từ Thái Cổ"],"nguon":["@c0001"]},{"id":"cay-set-danh-dau-thon","name":"Cây sét đánh (gốc liễu già) đầu thôn","cn":"","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Cây bự đường kính hơn chục mét đầu Thạch Thôn, cành liễu duy nhất thu hết hào quang mây sớm; nơi tộc nhân cầu khấn Tế Linh.","detail":"Gốc cây sét đánh đầu thôn có đường kính hơn chục mét, chỉ còn một cành liễu duy nhất thu hết hào quang trong làn mây sớm rồi trở lại bình thường. Tộc nhân Thạch Thôn cúng tế cây như Tế Linh bảo hộ, cầu khấn trước mỗi chuyến săn.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0001"]},{"id":"goc-cay-set-danh","name":"Gốc cây sét đánh","cn":"","aliases":["Gốc liễu già"],"capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Cây liễu già ở đầu Thạch Thôn đường kính hơn chục mét, nơi tộc nhân cầu khấn Tế Linh.","detail":"Gốc cây sét đánh nằm ở đầu thôn, đường kính hơn chục mét, có cành liễu duy nhất thu ánh hào quang trong làn mây sớm — dáng vẻ khác thường. Đây là nơi tộc nhân Thạch Thôn tụ tập cầu khấn “Tế Linh” trước mỗi chuyến vào núi săn, xin bảo hộ bình an.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0001"]},{"id":"nui-sau-rung-ram-quanh-thach-thon","name":"Núi sâu rừng rậm quanh Thạch Thôn","capDo":"khac","parentId":"dai-hoang","blurb":"Vùng núi sâu rừng rậm bên ngoài Thạch Thôn nơi đội săn đi vào, đầy mãnh cầm cự thú.","detail":"Bên ngoài thôn (vốn được cây liễu già bảo hộ) là núi sâu rừng rậm đầy mãnh cầm cự thú. Mấy đêm trước có cự thú siêu cấp đi qua khiến đất trời rung chuyển, dẫm chết và làm bị thương vô số thú rừng; trong núi xuất hiện mấy dấu chân lớn hình dạng giống chân người dài gần trăm mét, báo hiệu chuyện bất thường thu hút các chủng tộc Thái Cổ tìm đến.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0002"]},{"id":"cay-lieu-gia","name":"Cây liễu già","aliases":["Gốc liễu già"],"capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Cây liễu già bảo hộ Thạch Thôn; bên cạnh có bục đá lớn dùng làm đài tế đặt xác thú săn.","detail":"Cây liễu già là vật bảo hộ Thạch Thôn khỏi mãnh cầm cự thú bên ngoài. Bên gốc liễu có bục đá lớn; tộc trưởng vác xác mấy chục con thú săn được đặt lên bục đá làm tế lễ — rõ ràng là một đài tế cỡ lớn.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0002"]},{"id":"dan-te-thach-thon","name":"Đàn tế","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Đàn tế cắt từ đá tảng dựng sát gốc liễu già, nơi Thạch Thôn cúng tế Tế Linh.","detail":"Đàn tế được cắt ra từ đá tảng, rộng rãi, dựng sát cạnh gốc cây liễu già. Trên mặt đàn chất đầy mãnh thú chồng đống cao như ngọn núi nhỏ; máu thú nhuộm hồng bục đá chảy theo hoa văn điêu khắc, kết hợp lông thú, vảy thú, sừng to tạo hơi thở hồng hoang thảm khốc. Là nơi cử hành đại lễ cúng tế mỗi lần săn bắn trở về.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0003"]},{"id":"rung-nguyen-thuy-dai-hoang","name":"Rừng núi nguyên thủy","capDo":"vuc","parentId":"dai-hoang","blurb":"Rừng rậm nguyên thủy đầy âm khí, độc trùng và hung thú, nằm sát Thạch Thôn trong Đại Hoang.","detail":"Núi rừng nguyên thủy rậm rạp đầy âm khí, độc trùng, hung thú như Hung Bưu, Xà Hủy, Ác Ma Viên. Bọn trẻ Thạch Thôn lẻn vào để tìm sào huyệt hung cầm.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0007"]},{"id":"rung-da-thach-lam","name":"Rừng đá","cn":"Thạch Lâm","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Khu rừng đá lớn gần Thạch Thôn, rải rác di cốt cự thú, nơi có sào huyệt Thanh Lân Ưng.","detail":"Khu rừng đá lớn ngập hung khí trong rừng nguyên thủy, rải rác di cốt cự thú trắng như tuyết — xương chim dài 50 mét, xương đầu to bằng cối xay. Trong rừng đá có vách núi cao đặt sào huyệt Thanh Lân Ưng.","theLucLienQuan":[],"nguon":["@c0007"]},{"id":"ngo-sao","name":"Ngô Sào","capDo":"khac","parentId":"rung-da-thach-lam","blurb":"Tổ khổng lồ của Thanh Lân Ưng trên vách đá, làm bằng cành Ngô Mộc đen, còn to hơn nhà ở Thạch Thôn.","detail":"Tổ khổng lồ dài mười mét nằm trên vách đá cao khoảng 300 mét, làm bằng cành Ngô Mộc đen, đường kính hơn mười mét. Quanh tổ có xương lớn còn dính máu, xương đầu Long Giác Tượng với lỗ móng vuốt. Bên trong trải Kim Ti Thảo và có ba quả trứng Thanh Lân Ưng.","theLucLienQuan":[],"nguon":["@c0007"]},{"id":"thach-dong-song-ngam","name":"Thạch động (nối sông ngầm)","cn":"","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Động sâu ẩm ướt ẩn sau bụi dây leo gần Thạch Thôn, nối liền sông ngầm dưới đất.","detail":"Một thạch động sâu, ẩm ướt, gió lạnh, ẩn sau bụi dây leo gần Thạch Thôn, bên trong nối liền sông ngầm dưới lòng đất. Thạch Hạo tìm ra nơi này khi đuổi theo một con chim tước đỏ như máu suýt lạc đường. Khi bị Thanh Lân Ưng truy sát, đám nhóc Thạch Thôn chui vào động chạy sâu mấy chục mét để ẩn nấp; con hung cầm cào xé nham thạch mở rộng cửa động đuổi theo.","theLucLienQuan":["thach-thon-dia-danh"],"nguon":["@c0009"]},{"id":"goc-lieu-gia-dan-te-sat","name":"Gốc liễu già (đàn tế sát Thạch Thôn)","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Cây liễu cháy đen bên đàn tế sát nhà tộc trưởng, khiến ma cầm sợ không dám xâm nhập.","detail":"Gốc liễu già cháy đen đặt cạnh đàn tế sát trước nhà tộc trưởng Thạch Thôn. Thanh Lân Ưng thấy nó thì giật mình không dám xâm nhập thôn. Cuối chương gốc liễu chợt động, mây màu lục bích uốn lượn quanh cành liễu xanh duy nhất như những sợi xích thần vuốt qua một quả trứng khiến nó tỏa hào quang — vật thần bí ẩn giấu của Thạch Thôn.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0010"]},{"id":"sau-day-nui-dai-chien-thai-co","name":"Sâu trong dãy núi (nơi đại chiến Thái Cổ)","capDo":"vuc","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Vùng sâu trong dãy núi, hai năm trước xuất hiện sơn bảo và xảy ra đại chiến Thái Cổ.","detail":"Hai năm trước sâu trong dãy núi xuất hiện sơn bảo thu hút chủng tộc Thái Cổ, gây ra đại chiến với ánh lửa đỏ thiêu vỡ bầu trời cháy mấy chục ngày liền, nhìn từ Thạch Thôn cũng thấy. Có Hỏa Thú (nghi Thần Tước) ẩn sâu trong núi.","theLucLienQuan":[],"nguon":["@c0010"]},{"id":"khu-san-ban-thach-thon","name":"Khu săn bắn của Thạch Thôn","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Khu vực đội săn Thạch Thôn hoạt động.","detail":"Khu vực đội săn Thạch Thôn hoạt động; bị người Bái Thôn xâm nhập tranh mồi, dẫn tới việc cha Bì Hầu bị bắn trọng thương.","theLucLienQuan":["Thạch Thôn","Bái Thôn"],"nguon":["@c0012"]},{"id":"ranh-gioi-hai-thon","name":"Ranh giới hai thôn","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Khu vực giáp ranh giữa Thạch Thôn và Bái Thôn, nơi Bái Thôn vượt giới đào bẫy thú.","detail":"Vùng giáp ranh giữa hai thôn cách nhau mấy chục dặm; người Bái Thôn nhiều lần vượt giới đào bẫy thú với thiết mâu dưới đáy hố khiến người Thạch Thôn suýt bị đâm thủng.","theLucLienQuan":["Thạch Thôn","Bái Thôn"],"nguon":["@c0013"]},{"id":"nui-da-sup-do-toan-nghe","name":"Núi đá sụp đổ (nơi Toan Nghê tọa hóa)","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Tòa núi đá đổ nát nơi Toan Nghê chết, tâm điểm quần thú bạo động tranh đoạt.","detail":"Tòa núi đá đổ nát nơi Toan Nghê tọa hóa, tràn ngập khí tức khủng bố của Vạn Thú Vương chết đi. Nơi đây yên tĩnh như chết, phi cầm tẩu thú chạy sạch, trở thành tâm điểm của quần thú bạo động và cuộc tranh đoạt di thể giữa các thế lực.","theLucLienQuan":["Thạch Thôn","Ba thôn làng khác"],"nguon":["@c0018"]},{"id":"con-song-trong-nui","name":"Con sông trong núi","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Đường thủy trong dãy núi, nơi đại xà và cá lớn màu vàng phục kích.","detail":"Con sông chảy trong dãy núi nguyên thủy, là đường người ba thôn nhảy xuống để chạy trốn quần thú. Dưới sông có đại xà dài mấy chục mét và cá lớn màu vàng dài mười mấy mét phục kích, nuốt chửng và cắn xé những kẻ trốn chạy.","theLucLienQuan":[],"nguon":["@c0018"]},{"id":"vung-nui-tranh-doat-toan-nghe","name":"Vùng núi tranh đoạt (ngọn núi đá sụp đổ)","cn":"","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Khu vực ngoại vi dãy núi, nơi mấy trăm hung thú tụ tập tranh đoạt thi thể Toan Nghê.","detail":"Khu vực ngoại vi dãy núi nguyên thủy, quanh ngọn núi đá đã sụp đổ nơi Toan Nghê tọa hóa. Mấy trăm con hung thú, hung cầm cường đại tụ tập chém giết lẫn nhau, đào cự thạch để tìm bảo thể Toan Nghê nuốt vào tiến hóa thành bá chủ sơn lâm. Cây cối đổ rạp, đất đẫm máu. Đây cũng là nơi Thanh Lân Ưng là kẻ săn mồi đỉnh cấp ở vùng ngoại vi, ít khi bị thương nếu không vào sâu trong dãy núi. Cuối cùng bảo thể của Thái Cổ Di Chủng Toan Nghê lộ ra giữa đá núi, mở ra cuộc tranh đoạt lớn.","theLucLienQuan":["thach-thon-dia-danh"],"nguon":["@c0019"]},{"id":"sau-day-nui-ngoai-vi-toan-nghe","name":"Sâu trong dãy núi / khu vực ngoại vi","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Khu vực nơi Toan Nghê, Ác Ma Viên, Ly Hỏa Ngưu Ma và các bá chủ xưng tôn tranh đoạt.","detail":"Khu ngoại vi rừng núi nơi Thanh Lân Ưng là bá chủ. Sâu trong dãy núi có những cường giả như Ác Ma Viên với huyết thống vương giả cực cao và Ly Hỏa Ngưu Ma. Đây là nơi diễn ra cuộc đại loạn tranh đoạt bảo thể Toan Nghê.","theLucLienQuan":[],"nguon":["@c0020"]},{"id":"vung-dat-tru-phu-ngua-vay-sung","name":"Vùng đất trù phú (bộ lạc Ngựa vảy sừng)","capDo":"vuc","parentId":null,"blurb":"Bình nguyên trải dài, núi sông hùng vĩ, nơi bộ lạc Ngựa vảy sừng cư ngụ.","detail":"Vùng đất trù phú xa xôi với bình nguyên trải dài và núi sông hùng vĩ, là địa bàn của bộ lạc lớn cưỡi Ngựa vảy sừng.","theLucLienQuan":["Bộ lạc Ngựa vảy sừng"],"nguon":["@c0028"]},{"id":"ho-nuoc-xanh-lam","name":"Hồ nước xanh lam","capDo":"khac","parentId":null,"blurb":"Hồ lớn nước xanh như biển, nhiều đảo nhỏ như bàn cờ sao.","detail":"Hồ nước lớn xanh như biển với nhiều đảo nhỏ rải rác như bàn cờ sao, là nơi thế lực bên hồ xanh đặt cung điện và bọn nhóc cưỡi Giao lướt mặt nước.","theLucLienQuan":["Thế lực bên hồ xanh"],"nguon":["@c0028"]},{"id":"nui-tuyet-gia-toc-co","name":"Núi tuyết gia tộc cổ","capDo":"vuc","parentId":null,"blurb":"Núi cao phủ tuyết, tòa thành lớn ở trung tâm núi.","detail":"Vùng núi cao phủ tuyết với tòa thành lớn ở trung tâm núi, nơi gia tộc cổ xưa lánh đời từ Thời đại Thượng cổ cư ngụ.","theLucLienQuan":["Gia tộc cổ trên núi tuyết"],"nguon":["@c0028"]},{"id":"cuong-vuc-dai-vuc","name":"Cương vực (đại vực)","capDo":"vuc","parentId":"dai-hoang","blurb":"Vùng rộng lớn phải đi mấy triệu cây số mới tới tận cùng.","detail":"Một cương vực rộng lớn phải đi mấy triệu cây số mới tới tận cùng; ngoài đại địa còn có thế giới thần bí với siêu cấp đại tộc và kỳ tài ngút trời. Thạch Vân Phong mới đi ra ngoài khoảng bốn mươi nghìn cây số.","theLucLienQuan":[],"nguon":["@c0029"]},{"id":"tieu-co-son-tran","name":"Tiểu Cô Sơn Trấn","cn":"","capDo":"thanh","parentId":"cuong-vuc-dai-vuc","blurb":"Trấn nhỏ ngoài dãy núi, hơn hai nghìn nhân khẩu, cách Thạch Thôn hơn trăm dặm; nơi các bộ tộc lớn tụ tập.","detail":"Một trấn nhỏ ngoài dãy núi, hơn hai nghìn nhân khẩu, cách Thạch Thôn hơn một trăm dặm, có bia đá khắc ba chữ Tiểu Cô Sơn. Mấy ngày liền các bộ tộc lớn — La Phù Đại Trạch, Tử Sơn Tộc, Lôi Tộc — kéo đến, sân viện chật kín người, một bộ phận ở nhờ hộ dân, chuẩn bị cho cuộc so tài giữa các thiên tài trẻ.","theLucLienQuan":["La Phù Đại Trạch","Tử Sơn Tộc","Lôi Tộc"],"nguon":["@c0030","@c0048","@c0041"],"aliases":["Tiểu Sơn Trấn","Tiểu Cô Sơn Trấn"]},{"id":"te-linh-tieu-co-son","name":"Tế Linh Tiểu Cô Sơn","cn":"","capDo":"khac","parentId":"tieu-co-son-tran","blurb":"Ngọn núi đá có linh tính được người trong trấn tế bái lâu ngày, có thể đã sinh chân huyết kỳ dị.","detail":"Ngọn núi đá có linh tính tại Tiểu Cô Sơn Trấn, được người trong trấn tế bái lâu ngày, dâng hung thú làm tế phẩm; tương truyền có thể đã sinh chân huyết kỳ dị hiếm có. Động vào có thể chọc phải Sơn Thần, nên các bộ tộc kiêng dè không dám xâm phạm.","theLucLienQuan":[],"nguon":["@c0030"]},{"id":"te-linh-thon","name":"Tế linh thôn","cn":"","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Thôn có cây liễu bị sét đánh cháy chỉ còn cành non, được cho là chí bảo.","detail":"Nơi có cây liễu Tế linh bị sét đánh cháy chỉ còn cành non; cường giả các bộ tộc tụ đến tranh giành, coi là chí bảo hiếm thấy nhưng cảnh báo Tế linh có thể giết người.","theLucLienQuan":["Tế Linh"],"nguon":["@c0033"]},{"id":"tuyet-hai-van-thien-cung","name":"Tuyết Hải","cn":null,"capDo":"khac","parentId":null,"blurb":"Nơi thuộc Vân Thiên Cung, hai tiểu cô nương hứa dẫn Thạch Hạo đi xem.","detail":"Tuyết Hải là một địa danh thuộc thế lực Vân Thiên Cung. Hai tiểu cô nương Vân Thiên Cung dùng nơi này để dụ dỗ, hứa hẹn dẫn Thạch Hạo tới xem khi mời hắn gia nhập tông môn.","theLucLienQuan":["Vân Thiên Cung"],"nguon":["@c0039"]},{"id":"vung-nui-thuong-mang","name":"Vùng núi Thương Mãng","cn":"","capDo":"vuc","parentId":null,"blurb":"Dãy núi nơi Thạch thôn tọa lạc, cách bộ lạc Kim Lang hai mươi ngàn cây số.","detail":"Vùng núi Thương Mãng (Thương Mang) là dãy núi nơi Thạch thôn tọa lạc. Bộ lạc Kim Lang cách vùng núi này hai mươi ngàn cây số. Sau vụ Tế linh và xương Toan Nghê, khắp dãy núi này chấn động, thu hút các đại tộc và Chí cường giả kéo tới.","theLucLienQuan":["Thạch Thôn","Bộ lạc Kim Lang"],"nguon":["@c0041"]},{"id":"thanh-dao-giao-thuong","name":"Thánh đảo (Giao Thương)","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi đám Giao Thương trở về bẩm báo chuyện Thạch thôn.","detail":"Thánh đảo là nơi đám Giao Thương trở về bẩm báo, gây trận rống giận như Man giao Thái cổ xuất thế, chấn động vùng nước.","theLucLienQuan":["Giao Thương"],"nguon":["@c0041"]},{"id":"thuong-mang-son-mach","name":"Thương Mãng Sơn Mạch","cn":"","aliases":["Vùng núi Thương Mãng","Dãy núi Thương Mãng","Thương Mang sơn mạch"],"capDo":"vuc","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Dãy núi nguyên thủy nơi diễn ra đại chiến bốn sinh vật cực mạnh, bảo cốt trấn áp và báu vật hỗn độn xuất thế ở trung tâm.","detail":"Sâu trong dãy núi nguyên thủy, bốn sinh vật cực mạnh đại chiến tranh đoạt thánh vật; hơn mười khúc bảo cốt ngưng ký hiệu nguyên thủy rơi ra phân tán khắp sơn mạch để ổn định núi sông. Trung tâm sơn mạch nổ vang, loạn thạch vỡ nát, tiên quang xông trời khi hỗn độn chí bảo xuất thế.","theLucLienQuan":[],"nguon":["@c0046","@c0035"]},{"id":"quoc-gia-co-dai-truyen-thuyet","name":"Quốc gia cổ đại trong truyền thuyết","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia cổ đại được nhắc trong truyền thuyết, nơi chư cường ước ao chui vào để tránh họa.","detail":"Nơi các cường giả ước ao chui vào tránh đại họa khi tứ đại sinh linh hạ lệnh diệt chủng san bằng đại địa.","theLucLienQuan":[],"nguon":["@c0047"]},{"id":"vung-dat-muoi-van-dam","name":"Vùng đất phương viên mười vạn dặm","capDo":"vuc","parentId":"dai-hoang","blurb":"Khu vực bao gồm lãnh địa Lôi Tộc, Tử Sơn Tộc, Kim Lang, La Phù Đại Trạch, bị huyết tẩy thành tử địa nhuốm máu.","detail":"Vùng đất phương viên mười vạn dặm là khu vực rộng lớn chứa lãnh địa của bốn bộ tộc mạnh nhất (Lôi Tộc, Tử Sơn Tộc, Kim Lang, La Phù Đại Trạch) cùng Dực Tộc, Mộc Tộc. Sau cuộc đại chiến tứ chí tôn và huyết tẩy, cả vùng biến thành tử địa nhuốm máu, núi non sụp đổ hoặc bị cắt đứt, mặt đất rạn nứt.","theLucLienQuan":["Lôi Tộc","Tử Sơn Tộc","Bộ lạc Kim Lang","La Phù Đại Trạch"],"nguon":["@c0049"]},{"id":"than-son-hong-hoang-di-chung","name":"Thần Sơn","capDo":"khac","parentId":null,"blurb":"Nơi ở của sinh linh chí tôn Hồng Hoang Di Chủng, được hứa cho con nào nổi bật đi theo tu luyện.","detail":"Thần Sơn là địa điểm bí ẩn nơi ở của các sinh linh chí tôn tà ác. Hung thú mắt xanh hô hào huyết tẩy mười vạn dặm và hứa cho con nào nổi bật được đi theo tu luyện tại Thần Sơn.","theLucLienQuan":[],"nguon":["@c0049"]},{"id":"vung-dat-moi-ho-lon","name":"Vùng đất mới (hồ lớn trù phú)","capDo":"khac","parentId":null,"blurb":"Nơi Thạch Thôn dịch chuyển tới sau khi thoát không gian kỳ lạ — có sông cá Long Tu Ngư, hồ xanh biếc với đàn Ngũ Sắc Kê và đàn Độc Giác Thú.","detail":"Vùng đất trù phú hoàn toàn khác núi rừng quen thuộc, nơi Thạch Thôn xuất hiện lại sau khi thoát không gian kỳ lạ. Có con sông với cá lớn vảy vàng Long Tu Ngư, hồ xanh biếc với đàn Ngũ Sắc Kê và đàn Độc Giác Thú (Lân Mã biến dị) ánh bạc uống nước bên hồ. Nhóc tỳ có ký ức mơ hồ đã từng thấy nơi này, khiến tộc trưởng và chủ sự biến sắc.","nguon":["@c0050"]},{"id":"khong-gian-ky-la-mo-suong","name":"Không gian kỳ lạ (mờ sương)","capDo":"khac","parentId":null,"blurb":"Không gian hỗn độn có ánh sáng trắng bạc, sương mù lượn lờ, vây Thạch Thôn hơn hai tháng trước khi vỡ ra.","detail":"Không gian kỳ lạ mờ sương mà cả Thạch Thôn tỉnh lại sau khi Liễu Thần thi triển đại pháp cứu thôn khỏi thú triều. Ánh sáng trắng bạc như bình minh, sương mù lượn lờ, không ai biết mình đang ở đâu. Sau hơn hai tháng, bầu trời nứt ra, màn sương vỡ như bình ngọc, cả thôn thoát khốn ra vùng đất mới.","nguon":["@c0050"]},{"id":"vung-tu-dia-tram-ngan-dam","name":"Vùng tử địa trăm ngàn dặm","cn":"","capDo":"vuc","parentId":null,"blurb":"Cương vực rộng lớn bị sinh linh chí tôn hủy diệt hoàn toàn trong đại kiếp nạn.","detail":"Một vùng cương thổ trăm ngàn dặm bị hủy diệt trong trận đại chiến kinh thiên động địa. Đại địa đứt gãy, có dấu chân khổng lồ giẫm đổ dãy núi, hố móng vuốt của hung cầm, sông núi nóng chảy sôi ùng ục. Trong phạm vi này các thế lực Lôi Tộc, Tử Sơn, La Phù Đại Trạch, bộ lạc Kim Lang cùng mấy ngàn vạn nhân khẩu bị diệt tuyệt. Thanh Lân Ưng và đám chim cảm ngộ được chiến ý từ các vết tích để lại.","theLucLienQuan":[],"nguon":["@c0052"]},{"id":"ho-nuoc-kho-can","name":"Hồ nước khô cạn","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi tưởng là thung lũng, thực ra là một hồ nước đã khô cạn vì trận đại chiến.","detail":"Nơi thoạt nhìn tưởng là thung lũng nhưng thực ra là một hồ nước, đã khô cạn vì trận đại chiến kinh thiên động địa trước đó. Dưới đáy hồ khô cạn có một sinh linh nằm bất động bị đất cát phủ như bị lấp nhiều năm, chỉ còn một con mắt sáng cho thấy nó chưa chết — một con khỉ dài một thước có ba cái tay.","theLucLienQuan":[],"nguon":["@c0052"]},{"id":"ho-lon-kho-can-chien-truong-co","name":"Hồ lớn khô cạn (chiến trường cổ)","capDo":"khac","parentId":"dai-hoang","blurb":"Hồ lớn đã khô cạn hơn một năm, quần sơn xung quanh bị cắt đứt còn một nửa như bị vật báu quét ngang, âm trầm tử khí.","detail":"Nơi Tiểu Thạch Hạo phát hiện sinh linh Chu Yếm dài một xích kẹt dưới đáy bùn cứng. Cảnh tượng quần sơn bị cắt đứt gợi ý từng là chiến trường cổ nơi vật báu quét ngang.","theLucLienQuan":[],"nguon":["@c0053"]},{"id":"ho-xanh-ngoc-bich-thach-thon","name":"Hồ xanh ngọc bích","capDo":"khac","parentId":"than-son-hong-hoang-di-chung","blurb":"Hồ nước xanh ngọc bích ở Thạch thôn, nơi đám nhóc tu hành, có cá vàng kim và dị cầm.","detail":"Hồ ở Thạch thôn nơi đám nhóc khổ tu Cốt văn, có cá vàng kim và dị cầm như Xích Vũ Hạc, Tiểu Loan Điểu; đầu hồ là cây liễu (Liễu Thần).","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0054"]},{"id":"te-linh-thon-cay-lieu-set-danh","name":"Tế linh thôn (cây liễu bị sét đánh)","capDo":"khac","parentId":"rung-nguyen-thuy-dai-hoang","blurb":"Một cây liễu già cháy đen chỉ còn một cành non, được các cường giả cho là chí bảo.","detail":"Cây liễu già bị sét đánh cháy đen, trải đại kiếp nạn tái sinh chỉ còn một cành non. Các cường giả ngoài kéo tới cho đây là chí bảo và tranh đoạt, nhưng người lớn cảnh báo không được động tới Tế linh vì chúng có thể giết người.","theLucLienQuan":["Đại bộ lạc chư cường"],"nguon":["@c0033"]},{"id":"thach-thon","name":"Thạch thôn","capDo":"khac","parentId":null,"blurb":"Bộ tộc của nhóc tỳ, nơi diễn ra việc tẩy lễ.","detail":"Thôn của Cổ khí tộc, nơi người thôn tụ tập chứng kiến quá trình tẩy lễ và lột xác của nhóc tỳ. Trong tộc lưu giữ nhiều đỉnh nặng và bảo đỉnh chế thuốc tổ truyền.","theLucLienQuan":["Bái Thôn"],"nguon":["@c0032"]},{"id":"thach-lam","name":"Thạch Lâm","aliases":["rừng đá"],"capDo":"khac","parentId":null,"blurb":"Khu rừng đá nơi có tổ Thanh Lân Ưng, cách Thạch Thôn không xa.","detail":"Khu rừng đá thuộc vùng tương đối an toàn quanh Thạch Thôn, chưa tới phạm vi hung vật nguy hiểm sâu trong núi lớn. Trên vách đá nơi đây có tổ Thanh Lân Ưng, nơi lũ trẻ Thạch Thôn trèo lên trộm ba quả trứng hung cầm rồi chạy khỏi trước khi con chim về tổ.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0008"]},{"id":"cam-dia-toan-nghe","name":"Vùng cấm địa Toan Nghê","capDo":"khac","parentId":null,"blurb":"Khu núi rừng sâu nơi Toan Nghê xé xác hung thú, biến thành cấm địa không bóng chim muông.","detail":"Khu núi rừng sâu bị con Toan Nghê xé xác nhiều hung thú, biến thành cấm địa. Sau bốn ngày một tiếng rống kinh thiên động địa, Toan Nghê từ sâu trong núi ra khu ngoại vi tìm chỗ chôn thân và cuối cùng chết trong một sơn động; Thạch Thôn kéo tới đây để lấy di thể.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0017"]},{"id":"day-nui-sau-thach-thon","name":"Dãy núi sâu","aliases":["nơi sâu nhất của dãy núi"],"capDo":"vuc","parentId":"dai-hoang","blurb":"Nơi sâu nhất của dãy núi gần Thạch thôn, dựng dục Sơn bảo, nhiều cổ quái.","detail":"Nơi sâu nhất của dãy núi gần Thạch thôn, dựng dục Sơn bảo. Tại đây nổ ra đại chiến giữa chim Bé Hồng và sinh vật khổng lồ móng vàng kim, núi non bị cào nát nóng chảy thành dung nham. Mây đen dày ngăn tầm mắt khiến Thạch thôn không thấy rõ; nhiều cổ quái ẩn náu, người thôn không dám xâm nhập.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0028"]},{"id":"rung-nguyen-thuy-thach-thon","name":"Rừng nguyên thủy","capDo":"khac","parentId":"thach-thon","blurb":"Mảnh rừng sâu thăm thẳm quanh Thạch thôn, nơi tùy tùng La Phù Đại Trạch ẩn nấp và các cường giả chạy trốn.","detail":"Rừng nguyên thủy sâu thăm thẳm bao quanh Thạch thôn. Hơn chục cường giả La Phù Đại Trạch nấp trong rừng chờ đánh giết cây liễu; sau khi đại bại, các tộc chạy trốn vào rừng nguyên thủy.","theLucLienQuan":["La Phù Đại Trạch","Thạch Thôn"],"nguon":["@c0040"]},{"id":"con-song-lon-phuong-tay","name":"Con sông lớn phương Tây","cn":"","capDo":"khac","parentId":null,"blurb":"Con sông lớn cách Thạch thôn hơn nửa cây số về phía Tây.","detail":"Nơi tộc chủ La Phù Đại Trạch đứng khi điều khiển Bảo thuật hung giao, cách Thạch thôn hơn nửa cây số. Cành liễu vọt tới tận con sông này, chém đứt hắn làm hai.","theLucLienQuan":["La Phù Đại Trạch"],"nguon":["@c0044"]},{"id":"than-son-thai-co","name":"Thần Sơn Thái Cổ","cn":"","capDo":"khac","parentId":null,"blurb":"Cổ địa nguyên thủy nguy hiểm, nơi trú ẩn của Chân Hống.","detail":"Thần Sơn Thái Cổ là cổ địa nguyên thủy cực kỳ nguy hiểm, nơi trú ẩn của Chân Hống. Đây được nhắc tới như vùng đất mà Thánh dược mọc ra — thứ dược liệu cha mẹ Thạch Hạo lên đường tìm kiếm để trị tận gốc bệnh tình cho nó.","theLucLienQuan":[],"nguon":["@c0052"]},{"id":"ho-lon-kho-can","name":"Hồ lớn khô cạn","cn":"","capDo":"khac","parentId":"dai-hoang","blurb":"Hồ lớn đã khô cạn hơn một năm, quần sơn xung quanh bị cắt đứt còn một nửa như bị vật báu quét ngang, âm trầm tử khí.","detail":"Vùng hồ lớn khô cạn hơn một năm, giống một chiến trường cổ: các dãy núi xung quanh bị cắt đứt còn một nửa như bị vật báu quét ngang, phảng phất tử khí. Chính dưới đáy bùn cứng như đá nơi đây, Thạch Hạo tìm thấy sinh linh di chủng Chu Yếm bị kẹt một chân.","theLucLienQuan":[],"nguon":["@c0053"]},{"id":"chu-vuc","name":"Chư vực","aliases":[],"capDo":"gioi-dien","parentId":null,"blurb":"Thế giới vô biên mênh mông không thấy bến bờ.","detail":"Chư vực là thế giới rộng lớn không thấy bờ bến; những gì dân Thạch Thôn biết chỉ là một góc nhỏ. Nơi tận cùng mặt đất có các tộc siêu cấp và lãnh địa vương hầu hùng mạnh.","theLucLienQuan":[],"nguon":["@c0006"]},{"id":"son-mach-hai-thon","name":"Sơn mạch (nơi hai thôn sinh sống)","capDo":"vuc","parentId":"chu-vuc","blurb":"Dãy núi chung của Thạch Thôn và Bái Thôn, sâu bên trong có dị thú Thái Cổ Di Chủng.","detail":"Dãy núi rộng lớn nơi Thạch Thôn và Bái Thôn cùng cư ngụ. Sâu trong sơn mạch thi thoảng có Thái Cổ Di Chủng nảy sinh xung đột chém giết lẫn nhau, tàn phá mấy chục dặm rừng — Thạch Thôn từng gặp bãi xác dị thú với riêng Long Giác Tượng chết tám con cùng nhiều Nguyệt Tê trắng tinh và cự thú. Cũng có con Toan Nghê sâu trong núi phát điên gào thét chấn động quần sơn.","theLucLienQuan":["Thạch Thôn","Bái Thôn"],"nguon":["@c0013"]},{"id":"la-phu-dai-trach-dia-danh","name":"La Phù Đại Trạch","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Giao Bằng và Giao Tộc đến.","detail":"Vùng đất của thế lực La Phù Đại Trạch, tổ tiên từng lấy được truyền thừa Thái Cổ Hung Giao; giết Tế Linh cũng phải cẩn thận.","theLucLienQuan":["La Phù Đại Trạch","Giao Tộc"],"nguon":["@c0034"]},{"id":"day-nui-son-mach","name":"Dãy núi sơn mạch (nơi hai thôn)","capDo":"khac","parentId":null,"blurb":"Dãy núi chung của Thạch Thôn và Bái Thôn, sâu bên trong có dị thú Thái Cổ Di Chủng.","detail":"Sơn mạch nơi Thạch Thôn và Bái Thôn cùng sinh sống, cách nhau mấy chục dặm. Sâu trong núi thi thoảng có Thái Cổ Di Chủng nảy sinh xung đột chém giết lẫn nhau, tàn phá mấy chục dặm rừng và để lại những bãi thi thể mãnh thú như Long Giác Tượng, Nguyệt Tê; một con Toan Nghê từng phát điên gào thét chấn động quần sơn.","theLucLienQuan":["Thạch Thôn","Bái Thôn"],"nguon":["@c0013"]},{"id":"bai-thon-dia-danh","name":"Bái Thôn","cn":"","capDo":"khac","parentId":"dai-hoang","blurb":"Làng do Bái Lý Thanh làm tộc trưởng, giỏi tiễn thuật, phục kích cướp bảo thể Toan Nghê.","detail":"Một làng thuộc Đại Hoang, do lão tộc trưởng Bái Lý Thanh dẫn đầu. Người Bái Thôn giỏi tiễn thuật, hơn trăm người từng phục kích Thạch Hạo ở khu rừng núi ngoại vi để cướp bảo thể Toan Nghê chứa Thái Cổ chân huyết. Tế Linh của tộc sắp đột phá nên cần lượng lớn chân huyết, vì thế Bái Lý Thanh sẵn sàng phá quy củ không khai chiến của Đại Hoang.","theLucLienQuan":["Bái Thôn"],"nguon":["@c0023"]},{"id":"te-linh-thon-dia-danh","name":"Tế linh thôn","capDo":"khac","parentId":null,"blurb":"Thôn có Tế linh là cây liễu bị sét đánh cháy chỉ còn chồi non, được xem là chí bảo hiếm thấy.","detail":"Nơi các bộ tộc cường giả cưỡi Ngựa một sừng bạc, cưỡi Giao, đứng trên xương thú kéo đến. Đám con trời nhí phát hiện Tế linh và cược trân huyết thoát thai hoán cốt để tranh danh thiên tài số một, nhưng người lớn dặn không được động Tế linh.","theLucLienQuan":[],"nguon":["@c0033"]},{"id":"day-nui-phia-sau-thach-thon","name":"Dãy núi phía sâu Thạch thôn","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Dãy núi phía sâu quanh Thạch thôn, nơi cường giả các thế lực viện cớ muốn vào tìm hiểu huyền bí Sơn bảo.","detail":"Cường giả các thế lực La Phù Đại Trạch, Tử Sơn tộc, Lôi Tộc, bộ lạc Kim Lang, Vân Thiên Cung trú đóng quanh Thạch thôn viện cớ muốn vào dãy núi phía sâu tìm hiểu huyền bí Sơn bảo; tộc trưởng Thạch thôn không cho người đi vì cần tọa hóa cực lớn.","theLucLienQuan":["Thạch thôn","La Phù Đại Trạch","Tử Sơn Tộc","Lôi Tộc","Bộ lạc Kim Lang","Vân Thiên Cung"],"nguon":["@c0036"]},{"id":"ho-canh-thach-thon","name":"Hồ bên Thạch Thôn","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Hồ nước xanh với thảm cỏ cạnh Thạch Thôn, quanh đó có Long Tu Ngư, Tiểu Loan Điểu, Độc Giác Thú, Ngũ Sắc Kê.","detail":"Hồ nước trong xanh ven Thạch Thôn, có thảm cỏ; nơi tụ tập của nhiều dị thú như Long Tu Ngư, Tiểu Loan Điểu, Độc Giác Thú và Ngũ Sắc Kê.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0051"]},{"id":"nhan-hoang-thanh","name":"Nhân Hoàng Thành","capDo":"thanh","parentId":"co-quoc-nhan-hoang","blurb":"Thần thành nguy nga hùng vĩ của cổ quốc; riêng tường thành như dãy núi liên miên, nơi tin tức bát hoang tụ về.","detail":"Nơi Nhân Hoàng ngự trị; khi tin Thập Ngũ Gia bắn chết Tỳ Hưu ở Bách Tộc Chiến Trường truyền về, cả Nhân Hoàng Thành chấn động.","theLucLienQuan":["Cổ quốc (Nhân Hoàng)"],"nguon":["@c0055"]},{"id":"bach-toc-chien-truong","name":"Bách Tộc Chiến Trường","capDo":"khac","parentId":null,"blurb":"Chiến trường trọng đại giữa trăm tộc; nơi Thập Ngũ Gia bắn chết một con Tỳ Hưu non khiến cả bát hoang chấn động.","detail":"Có tin đồn một con Tỳ Hưu trưởng thành huyết mạch thuần khiết muốn xông vào Bách Tộc Chiến Trường, báo hiệu đại loạn sắp tới.","theLucLienQuan":[],"nguon":["@c0055","@c0056"]},{"id":"thanh-ho-co-quoc","name":"Thánh Hồ","capDo":"khac","parentId":"co-quoc-nhan-hoang","blurb":"Hồ nước xanh biếc linh khí nồng nặc — cấm khu tu hành có Thái Cổ Di Chủng và hậu duệ Thần Cầm sinh sống.","detail":"Người thường không thể tới gần; mấy vạn thiết kỵ giáp trụ ngồi trên lưng hung thú canh gác khi Vương Hầu săn thú. Là nơi Lão Thập Ngũ bắn hạ Loan Điểu hậu duệ Thái Cổ Thần Cầm.","theLucLienQuan":["Cổ quốc (Nhân Hoàng)"],"nguon":["@c0055"]},{"id":"te-dan-te-troi-co-quoc","name":"Tế đàn tế trời cổ quốc","capDo":"khac","parentId":"co-quoc-nhan-hoang","blurb":"Tế đàn khổng lồ cao tận tầng mây, cổ xưa tang thương như tồn tại hàng tỉ năm — nơi Nhân Hoàng cả nước tế trời.","detail":"Khắc nhật nguyệt tinh hà, hung thú Thái Cổ, tiên dân Thượng Cổ, thần linh; trên tế đàn đặt thi thể Thái Cổ Di Chủng cùng vật báu và bảo dược, máu chảy về các đồ án.","theLucLienQuan":["Cổ quốc (Nhân Hoàng)"],"nguon":["@c0055"]},{"id":"vuong-hau-phu-thap-ngu-gia","name":"Vương hầu phủ Thập Ngũ gia","cn":"","capDo":"khac","parentId":"hoang-do-quoc-gia-co-nhan-toc","blurb":"Vương hầu phủ của Thập Ngũ gia trong quốc gia cổ Nhân tộc, được ví như động thiên phúc địa với cung điện xếp cụm, linh khí tràn ngập.","detail":"Vương hầu phủ tại quốc gia cổ Nhân tộc, nơi ở của gia tộc Thập Ngũ gia (ông nội Thạch Hạo). Khung cảnh như thiên cung nhân gian: kiến trúc cung điện trùng trùng xếp cụm, linh khí tràn ngập, bảo quang ẩn hiện, sương ánh sáng trôi nổi khắp nơi. Trong phủ có hồ nước trong vắt, rừng cây rộng lớn với chim quý như Xích Vũ Hạc, Loan Điểu, Ngũ Sắc Khổng Tước Vương bay lượn. Ngoài đại môn có thụy thú trấn giữ. Nội bộ do hai vị lão gia tử chủ sự, đông người hầu và cao thủ. Đây là nơi Thạch Hạo và Thạch Nghị lớn lên những năm đầu đời, cũng là nơi bí mật Chí Tôn cốt của Thạch Hạo được liệt vào hàng tuyệt mật.","theLucLienQuan":["quoc-gia-co-nhan-toc","vuong-hau-phu-thap-ngu-gia-the-luc"],"nguon":["@c0056"]},{"id":"hoang-do-quoc-gia-co-nhan-toc","name":"Hoàng đô quốc gia cổ Nhân tộc","cn":"","capDo":"thanh","parentId":null,"blurb":"Đô thành của quốc gia cổ Nhân tộc, nơi Nhân Hoàng đứng đầu và ban ý chỉ điều động chư hầu.","detail":"Hoàng đô của quốc gia cổ Nhân tộc, nơi Nhân Hoàng chi tộc ngự trị. Đây là trung tâm chính trị nơi tin dữ từ Bách tộc chiến trường (việc Thập Ngũ gia bắn chết con Tỳ Hưu huyết mạch tinh thuần) truyền về, và cũng là nơi Nhân Hoàng truyền ý chỉ điều động các lộ chư hầu đi tìm cứu Thập Ngũ gia sau khi lão bị Tỳ Hưu đuổi giết. Vương hầu phủ của Thập Ngũ gia là một trong những cụm chư hầu phủ nằm trong quốc gia cổ này. An toàn tuyệt đối trừ phi Thái cổ hung thú công phá tới.","theLucLienQuan":["quoc-gia-co-nhan-toc"],"nguon":["@c0056"]},{"id":"nam-cuong-quoc-gia-co","name":"Nam Cương","cn":"南疆","capDo":"vuc","parentId":null,"blurb":"Vùng biên cương phía nam nơi cha Thạch Hạo lên đường đi tìm Thập Ngũ gia mất tích sau trận truy sát của Tỳ Hưu.","detail":"Nam Cương là hướng mà cha Thạch Hạo (Thập Nhất đệ) cùng vợ quyết đi tới sau khi biết Thập Ngũ gia bị Tỳ Hưu đuổi giết mấy chục vạn dặm, bị chém đứt một cánh tay và dùng Thần trận bảo cốt Thái cổ di chủng thoát mạng nhưng tăm tích không rõ. Đây là vùng biên cương xa xôi nằm ngoài quốc gia cổ Nhân tộc, tiếp giáp hoặc kề cận Bách tộc chiến trường, nơi được cho là Thập Ngũ gia có thể còn ẩn náu sau khi thoát chết.","theLucLienQuan":[],"nguon":["@c0056"]},{"id":"trang-vien-chiet-cot-luc-tau","name":"Trang viên chiết cốt của Lục tẩu","cn":"","capDo":"khac","parentId":"hoang-do-quoc-gia-co-nhan-toc","blurb":"Trang viên bên ngoài Vương hầu phủ mà Lục tẩu lừa Thạch Hạo tới để chiết Chí Tôn cốt, bên trong có mật thất dưới lòng đất.","detail":"Trang viên nằm bên ngoài Vương hầu phủ Thập Ngũ gia. Lục tẩu dùng cớ đưa Thạch Nghị và Thạch Hạo tới đây để xem hậu duệ Thái cổ Thần cầm, thực chất là cạm bẫy. Vào trang viên rồi đi xuống một cung điện dưới lòng đất, thông đến mật thất — nơi Lục tẩu triệu bóng u linh thực hiện việc chiết Chí Tôn cốt của Thạch Hạo và cấy sang Thạch Nghị. Bên trong mật thất có giường lạnh băng dành cho nhóc tỳ (Thạch Hạo) và giường ngọc dành cho Nghị nhi, đặt cạnh nhau thể hiện đối xử hai bậc rõ rệt.","theLucLienQuan":["vuong-hau-phu-thap-ngu-gia-the-luc"],"nguon":["@c0056"]},{"id":"mat-that-chiet-cot","name":"Mật thất chiết cốt","cn":"","capDo":"khac","parentId":"trang-vien-chiet-cot-luc-tau","blurb":"Mật thất dưới lòng đất bên trong trang viên của Lục tẩu, nơi diễn ra ca phẫu thuật chiết Chí Tôn cốt.","detail":"Căn phòng kín dưới lòng đất, nằm sâu bên dưới trang viên của Lục tẩu, tiếp cận qua một cung điện ngầm. Đây là nơi bóng u linh dùng đao bạc cứa lồng ngực Thạch Hạo để chiết Chí Tôn cốt, sau đó dùng ngân đao rạch lồng ngực Nghị nhi để cấy Chí Tôn cốt vào. Khi Chí Tôn cốt được tách khỏi lồng ngực nhóc tỳ, ánh thần tính từ đoàn sáng chói lọi tỏa ra chói cả tòa mật thất khiến linh hồn người ta run rẩy. Bên trong bố trí một giường lạnh băng cho nhóc tỳ và một giường ngọc cho Nghị nhi.","theLucLienQuan":[],"nguon":["@c0056"]},{"id":"phu-de-thach-toc","name":"Phủ đệ Thạch Tộc","capDo":"khac","parentId":null,"blurb":"Quần thể cung điện liên miên của Thạch Tộc, khí thế như Thiên cung giữa nhân gian.","detail":"Phủ đệ to lớn của Thạch Tộc, cung điện liên tiếp, khí thế uy nghiêm như Thiên cung. Nơi diễn ra đại hội trưởng lão bàn về Chí Tôn cốt: mười mấy lão tổ bậc cao bị triệu ra khỏi bế quan, phù văn dày đặc lập loè trong đại điện, sấm sét đan xen có thể bộc phát bất cứ lúc nào. Sau đó Thạch Tử Lăng trở về, cầm Hoàng Kim thần mâu phá tan một mảnh cung điện, xông về nhánh Thạch Nghị, đánh bay chư lão can ngăn và giết chú ruột của Nghị nhi ngay tại đây.","theLucLienQuan":["thach-toc"],"nguon":["@c0058"]},{"id":"hoang-do-thach-toc","name":"Hoàng Đô","capDo":"thanh","parentId":null,"blurb":"Kinh đô nơi Thạch tộc Vương tộc đóng — Thập Ngũ Gia và Thạch Tử Lăng nổi danh cường đại tại đây.","detail":"Hoàng Đô là nơi Thạch tộc Vương tộc Hoàng thân trú đóng. Thập Ngũ Gia từng chấn động Hoàng Đô với chiến tích hai mũi tên bắn chết Thái Cổ Di Chủng Loan Điểu và thú con Tỳ Hưu; thực lực Thạch Tử Lăng cũng chấn động nơi này.","theLucLienQuan":["Thạch tộc","Nhánh Thạch Nghị","Nhánh Thập Ngũ Gia"],"nguon":["@c0059"]},{"id":"cu-dia-nhanh-thach-nghi","name":"Cứ địa nhánh Thạch Nghị","capDo":"khac","parentId":"hoang-do-thach-toc","blurb":"Quần cung điện của nhánh Thạch Nghị trong Thạch tộc — nơi bày sát trận bảo cốt và diễn ra cuộc tàn sát.","detail":"Nơi ở của nhánh nhà Thạch Nghị trong Thạch tộc tại Hoàng Đô, gồm quần cung điện, sát trận bảo cốt và sân bãi tử sĩ. Trong chương bị Thạch Tử Lăng đánh nát: bảo cốt nổ tung, cung điện đổ, hơn trăm tử sĩ Vương tộc bị tàn sát.","theLucLienQuan":["Nhánh Thạch Nghị"],"nguon":["@c0059"]},{"id":"ngoai-vuc","name":"Ngoại Vực","capDo":"khac","parentId":null,"blurb":"Khái niệm không gian xa xôi như hành tinh khác/đại lục khác — dùng để so sánh ánh sáng từ chuỗi cốt châu.","detail":"Vùng xa xôi được nhắc đến như hành tinh khác hay đại lục khác. Trong chương dùng làm ẩn dụ: ánh sáng của chuỗi cốt châu Bảo Cụ lấp lánh như đám sao từ Ngoại Vực bay tới.","theLucLienQuan":[],"nguon":["@c0059"]},{"id":"man-hoang-kho-dia","name":"Man hoang khổ địa","capDo":"khac","parentId":null,"blurb":"Vùng man hoang khổ ải mà các tông lão Thạch tộc dọa trấn áp và đuổi Thạch Tử Lăng tới nếu hắn không chịu điều kiện của tộc.","detail":"Được nhắc như nơi lưu đày bất mãn: các tông lão dùng làm lời đe dọa trong khi vây công Thạch Tử Lăng tại phủ đệ.","theLucLienQuan":["Thạch Tộc"],"nguon":["@c0061","@c0062"],"aliases":["Khổ hoang chi địa"]},{"id":"to-dia-thu-hai-man-hoang","name":"Tổ địa thứ hai","cn":"","capDo":"khac","parentId":"man-hoang-kho-dia","blurb":"Trang viên rộng lớn nhưng cũ nát ở biên cương Man Hoang khổ địa, nơi tổ tiên Thạch gia từng lớn lên và nay dùng làm chỗ đày tộc nhân phạm đại tội.","detail":"Một trang viên rộng lớn nhưng cũ nát nằm ở vùng Man Hoang khổ địa, được xem là tổ địa thứ hai của Thạch tộc — nơi tổ tiên Thạch gia từng lớn lên. Về sau nó trở thành chốn đày ải những tộc nhân phạm đại tội. Cả nhà Thạch Tử Lăng bị đày tới đây sau đại chiến ở Hoàng Đô; bốn lão già từng uy danh hiển hách cũng bị giam ở nơi này vì đại tội, phẫn nộ trước việc Thạch Tử Lăng bị đày.","theLucLienQuan":[],"nguon":["@c0062"]},{"id":"to-dia-chinh-thuc-thach-toc","name":"Tổ địa chính thức Thạch tộc","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi thần bí đầy truyền thuyết của Thạch tộc, tương truyền có thể sinh ra Thần; tổ tiên Thạch tộc từ đó đi ra khai sáng Cổ quốc, nay đã bị cắt liên hệ theo Tổ huấn.","detail":"Tổ địa chính thức của Thạch tộc là nơi thần bí đầy truyền thuyết, tương truyền có thể sinh ra Thần. Tổ tiên Thạch tộc từ nơi này đi ra, khai sáng vô tận huy hoàng và lập nên một Cổ quốc. Theo Tổ huấn, liên hệ với tổ địa này đã bị cắt đứt. Tứ tổ lén trao cho Thạch Tử Lăng một tấm tàn đồ chỉ đường dẫn tới đây, mở ra tuyến hành trình tìm kiếm để cứu Hạo nhi.","theLucLienQuan":[],"nguon":["@c0062"]},{"id":"thai-co-than-son-c0062","name":"Thái Cổ Thần Sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi cực kỳ nguy hiểm, không thể xông loạn; tương truyền có các sinh vật Vô Thượng như Tê Cư, Chân Hống, Kim Sí Đại Bằng, gặp phải sẽ mất mạng.","detail":"Thái Cổ Thần Sơn là một nơi cực kỳ nguy hiểm mà mấy lão nhân cảnh báo không thể xông bừa vào. Tương truyền nơi đó có các sinh vật Vô Thượng như Tê Cư, Chân Hống, Kim Sí Đại Bằng — kẻ gặp phải sẽ mất mạng. Thạch Tử Lăng gửi hi vọng tìm được tổ địa qua tấm tàn đồ, chỉ khi vạn bất đắc dĩ mới vào Thái Cổ Thần Sơn; y thề nếu tìm tổ địa bất thành sẽ đi khắp Man Hoang tìm nơi này để hái thánh dược cứu Hạo nhi. Anchor: 「Thái Cổ Thần Sơn cũng không phải là nơi có thể xông loạn」.","theLucLienQuan":[],"nguon":["@c0062"]},{"id":"thac-nuoc-da-bay-muoi-dam","name":"Thác nước đá ngoài bảy mươi dặm","capDo":"khac","parentId":"thuong-mang-son-mach","blurb":"Vùng ba con sông lớn giao nhau chảy qua núi đá tạo thác lũ dữ dội, nơi Liễu Thần chỉ cho Thạch Hạo tu luyện nghịch dòng.","detail":"Nằm cách Thạch Thôn mấy chục dặm ngoài bảy mươi dặm, ba con sông lớn giao nhau đổ qua núi đá, tạo dốc đứng cao mấy trăm tới hơn ngàn mét; đá lớn từ mấy ngàn tới hơn vạn cân theo dòng nước rơi xuống. Thạch Hạo phải trèo ngược lũ, chống đá rơi, chặng cuối chống đá trên vạn cân — cảnh tượng tộc nhân nói còn nguy hiểm hơn chém giết vạn quân.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0064"]},{"id":"hoang-do-quoc-gia-co","name":"Hoàng đô (quốc gia cổ)","cn":"","capDo":"thanh","parentId":"quoc-gia-co-nhan-toc","blurb":"Đô thành của quốc gia cổ Nhân tộc, nơi Nhân Hoàng đứng đầu và ban ý chỉ.","detail":"Đô thành trung tâm quốc gia cổ Nhân tộc, nơi tin tức Thập Ngũ gia bắn chết con Tỳ Hưu truyền về và nơi Nhân Hoàng ban ý chỉ điều động chư hầu tìm cứu. Là trọng địa được bảo vệ — chỉ khi Thái cổ hung thú công phá Hoàng đô thì các phủ chư hầu mới lâm nguy.","theLucLienQuan":[],"nguon":["@c0056","@c0062"]},{"id":"trang-vien-ngoai-vuong-hau-phu","name":"Trang viên bên ngoài Vương hầu phủ","cn":"","capDo":"khac","parentId":"vuong-hau-phu-thap-ngu-gia","blurb":"Trang viên nơi Lục tẩu lừa Thạch Hạo tới, bên trong có cung điện dưới lòng đất và mật thất chiết xương.","detail":"Trang viên bên ngoài Vương hầu phủ mà Lục tẩu lấy cớ đưa Thạch Hạo tới để “xem hậu duệ Thái cổ Thần cầm”. Vào trang viên rồi đi xuống một cung điện dưới lòng đất dẫn tới mật thất — nơi thực hiện âm mưu chiết Chí Tôn cốt của Thạch Hạo.","theLucLienQuan":[],"nguon":["@c0056"]},{"id":"mat-that-chiet-xuong","name":"Mật thất chiết xương","cn":"","capDo":"khac","parentId":"trang-vien-ngoai-vuong-hau-phu","blurb":"Căn phòng kín dưới lòng đất nơi diễn ra ca chiết và cấy ghép Chí Tôn cốt.","detail":"Căn phòng kín trong cung điện dưới lòng đất của trang viên, nơi bóng u linh dùng đao bạc chiết Chí Tôn cốt khỏi nhóc tỳ rồi cấy sang Nghị nhi. Khi Chí Tôn cốt được tách ra, ánh thần tính từ nó tỏa chói cả tòa mật thất. Trong mật thất có giường lạnh băng cho nhóc tỳ và giường ngọc cho Nghị nhi.","theLucLienQuan":[],"nguon":["@c0056"]},{"id":"dia-cung-mat-that-thieu-phu","name":"Địa cung mật thất của thiếu phụ","capDo":"khac","parentId":null,"blurb":"Địa cung rộng lớn có cửa mà người thường không mở được, nơi thiếu phụ và bóng đen tiến hành cấy Chí Tôn Cốt.","detail":"Địa cung có lối vào chỉ chí cường giả trong tộc mới phá hủy nổi bằng sức; nơi thiếu phụ và bóng đen tiến hành cấy Chí Tôn Cốt và rút chân huyết. Tứ Thái Gia phá hủy lối vào xông vào bắt quả tang.","theLucLienQuan":["Thạch Tộc"],"nguon":["@c0057"]},{"id":"phu-de-thach-toc-hoang-do","name":"Phụ đệ Thạch tộc","cn":"","capDo":"khac","parentId":"hoang-do-thach-toc","blurb":"Sân và cung điện nơi diễn ra cuộc đối chất và đại chiến vì Chí Tôn Cốt trong Thạch tộc Hoàng Đô.","detail":"Khu phụ đệ trong Thạch tộc Hoàng Đô, nơi Thạch Tử Lăng đối chất với chi Thạch Uyên và đại chiến. Hàng loạt cung điện quanh sân bị tiếng phượng kêu và Bảo Thuật đánh sụp đổ; nơi này đã bị bảo cốt Thái Cổ Di Chủng phong tỏa để cách âm ngoại giới, giấu trận nội chiến khỏi Hoàng Đô.","theLucLienQuan":["Thạch tộc Hoàng Đô","Chi Thạch Uyên"],"nguon":["@c0060"]},{"id":"phu-de-thach-phu","name":"Phủ đệ Thạch Phủ","cn":"","capDo":"khac","parentId":"phu-de-thach-toc-hoang-do","blurb":"Nơi diễn ra trận chiến giữa Thạch Tử Lăng và các tông lão.","detail":"Phủ đệ của Thạch Phủ, bị bảo cốt Thái Cổ Di Chủng bao phủ khóa mảnh thiên địa, ngăn tiếng chiến đấu truyền ra ngoài.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0061"]},{"id":"thac-nuoc-da-tu-luyen","name":"Thác nước đá ngoài bảy mươi dặm","cn":null,"capDo":"khac","parentId":null,"blurb":"Nơi ba con sông lớn giao nhau chảy qua núi đá, tạo thác lũ dữ dội với đá mấy ngàn tới hơn vạn cân theo dòng rơi xuống.","detail":"Cách Thạch Thôn mấy chục dặm (ngoài bảy mươi dặm). Ba con sông lớn giao nhau chảy qua núi đá tạo thành dốc đứng cao mấy trăm tới hơn ngàn mét, đá lớn mấy ngàn tới hơn vạn cân theo dòng nước lũ rơi xuống. Liễu Thần chỉ định nơi này để Thạch Hạo tu luyện nghịch dòng — trèo ngược dòng lũ, chống đá rơi mà leo dốc đứng. Cảnh tượng nguy hiểm hơn chém giết vạn quân.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0064"]},{"id":"nguyen-thuy-son-mach","name":"Nguyên thủy sơn mạch","cn":"","aliases":["Rừng rậm nguyên thủy"],"capDo":"khac","parentId":null,"blurb":"Vùng rừng rậm núi non nguyên thủy, nơi Thần Lang và Tử Sơn Hầu chạy trốn vào sau khi bại trận ở Thạch Thôn.","detail":"Rừng rậm nguyên thủy hoang vu tiếp giáp khu vực Thạch Thôn; khi cây liễu bùng nổ, Thần Lang biến thành chùm sáng vàng và Tử Sơn Hầu hóa vầng thái dương màu tím đều chạy trốn vào nơi này để thoát khỏi tầm với của cây liễu.","theLucLienQuan":[],"nguon":["@c0045"]},{"id":"ho-sau-vi-tri-thach-thon-cu","name":"Hố sâu (vị trí Thạch thôn cũ)","cn":"","capDo":"khac","parentId":"dai-hoang","blurb":"Hố sâu đen ngòm không đáy tại nơi Thạch thôn từng cắm rễ, được cho là nơi thần linh chết đi.","detail":"Sau khi Thạch thôn biến mất, sinh linh mắt xanh thẳm phẫn nộ bắn hai tia chớp to như núi làm đại địa nứt toạc, tạo thành hố sâu đen ngòm. Nó nhận ra đây là nơi thần linh chết đi, tiếc rằng cây liễu đã đạt được chỗ tốt này.","theLucLienQuan":["Thạch thôn"],"nguon":["@c0048"]},{"id":"dia-cung-thieu-phu","name":"Địa cung mật thất thiếu phụ","capDo":"khac","parentId":"thach-toc","blurb":"Địa cung rộng lớn có cửa mà người thường không mở nổi, chỉ chí cường giả trong tộc mới phá được; nơi thiếu phụ cùng bóng đen cấy Chí Tôn Cốt.","detail":"Mật thất địa cung của thiếu phụ (mẹ Thạch Nghị) trong khuôn viên Thạch Tộc; lối vào chỉ chí cường giả trong tộc mới phá hủy nổi bằng sức. Tại đây thiếu phụ và bóng đen u linh moi Chí Tôn Cốt của Thạch Hạo cấy sang Thạch Nghị và rút chân huyết Hạo Nhi. Tứ Thái Gia phá hủy lối vào xông vào bắt quả tang.","theLucLienQuan":["Thạch Tộc"],"nguon":["@c0057"]},{"id":"co-dong-hai-lao-chu-su","name":"Cổ động của hai lão chủ sự","capDo":"khac","parentId":"thach-toc","blurb":"Nơi Tứ Thái Gia và Lão Ngũ ẩn tu tham ngộ diệu lý, bình thường không lộ diện.","detail":"Cổ động trong khuôn viên Thạch Tộc, nơi hai vị lão chủ sự bối phận cực cao (Tứ Thái Gia, Lão Ngũ) ẩn tu tham ngộ diệu lý; chỉ khi có biến cố lớn mới xuất hiện.","theLucLienQuan":["Thạch Tộc"],"nguon":["@c0057"]},{"id":"to-dia-thach-toc","name":"Tổ địa Thạch Tộc","capDo":"khac","parentId":null,"blurb":"Vùng đất tổ mà Thạch Tộc bị giới hạn; theo tổ huấn phải đoàn kết đối ngoại mới có ngày bước ra.","detail":"Tổ địa hiện thời của Thạch Tộc; tổ huấn cấm tàn sát lẫn nhau, tộc phải đoàn kết đối ngoại để bước ra tổ địa, đánh chiếm bờ cõi, cai trị hàng tỉ con dân, ngồi ngôi Nhân Hoàng.","theLucLienQuan":["Thạch Tộc"],"nguon":["@c0057"]},{"id":"vung-thac-nuoc-da","name":"Vùng thác nước đá","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Vùng thác nước như ngân hà chảy từ núi đá, nơi Thạch Hạo ngày ngày khổ luyện thân thể chống đá lăn và thác nước.","detail":"Vùng thác nước đá gần Thạch Thôn — thác trắng xóa chảy từ đỉnh núi đá xuống. Thạch Hạo ngày ngày tới đây chống thác trèo lên, để đá nặng mấy nghìn cân đập vào người mà chọi cứng. Trong ba tháng nó luyện thành mình đồng da sắt tại đây, rồi tu gần một năm mà đột phá Thập Vạn Cực Cảnh trên đỉnh núi đá.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0065"]},{"id":"ho-gan-thach-thon","name":"Hồ gần Thạch Thôn","capDo":"khac","parentId":"thach-thon-dia-danh","blurb":"Hồ gần thôn, nơi bọn trẻ ngâm mình hạ nhiệt sau khi uống bảo dược.","detail":"Hồ nước gần Thạch Thôn. Sau khi bọn trẻ trong thôn uống ngụm bảo dược từ đỉnh cổ, cơ thể yếu phun ánh sáng nên phải nhảy xuống hồ ngâm tới sáng để hạ nhiệt.","theLucLienQuan":["Thạch Thôn"],"nguon":["@c0065"]},{"id":"loan-thach-son","name":"Loạn thạch sơn","capDo":"khac","parentId":"dai-hoang","blurb":"Dãy núi đá trong Đại Hoang, nơi Thạch Hạo nâng cự thạch đi ngược lũ đá vào sâu khổ tu.","detail":"Dãy núi đá loạn thạch giữa Đại Hoang. Thạch Hạo nâng cự thạch mười vạn cân đi ngược dòng cơn lũ đá tiến sâu vào dãy núi, cứng đối cứng với thiên uy trong bão táp hồng thủy.","theLucLienQuan":[],"nguon":["@c0066"]},{"id":"duong-toi-co-quoc","name":"Đường tới Cổ quốc","cn":"","aliases":["Hành trình 300 nghìn dặm"],"capDo":"khac","parentId":null,"blurb":"Hành trình dài ba trăm ngàn dặm từ Thạch Thôn tới Cổ quốc, xuyên vô số dãy núi lớn đầy hung cầm khổng lồ.","detail":"Con đường phải đi qua không biết bao nhiêu dãy núi nguy nga, đầy hung cầm khổng lồ như chim lớn dài năm mươi mét phun lửa và hung cầm dài hơn trăm mét. Cưỡi Độc Giác Thú, Thạch Hạo chạy tới trưa được ba bốn nghìn dặm và phải né nhiều hung cầm.","theLucLienQuan":["Thạch Thôn","Cổ quốc"],"nguon":["@c0068"]},{"id":"vung-nui-tu-khi","name":"Vùng núi tử khí","aliases":["Núi trọc phủ tro nâu"],"capDo":"vuc","parentId":"dai-hoang","blurb":"Dãy núi lớn phủ tro nâu, không cây cỏ, nặng tử khí, nơi giam giữ một móng vuốt khổng lồ bị xích.","detail":"Dãy núi lớn nối nhau phủ tro nâu, không thảm thực vật, nham thạch nặng mấy vạn đến mười mấy vạn cân, ranh giới với vùng núi xanh tươi rất rõ rệt. Sâu trong núi vọng tiếng xích sắt ma sát; một móng vuốt màu xanh khổng lồ bị trói bởi cọng xích kim thò lên giãy giụa làm sập vài ngọn núi rồi buông xuôi biến mất, nghi là một Chí Cường Giả bị trói nhiều năm.","theLucLienQuan":[],"nguon":["@c0069"]},{"id":"bien-cuong-co-quoc","name":"Biên cương cổ quốc","aliases":[],"capDo":"khac","parentId":null,"blurb":"Đích đến của Thạch Hạo về phía mặt trời mọc, biên giới của cổ quốc.","detail":"Vùng biên cương của cổ quốc nằm về phía mặt trời mọc, là đích đến của nhóc tỳ khi băng qua Đại Hoang. Cuối chương nhóc tỳ còn cách nơi đây khoảng mười vạn dặm.","theLucLienQuan":[],"nguon":["@c0069"]},{"id":"song-thai-am","name":"Sông Thái Âm","cn":"","capDo":"khac","parentId":"dai-hoang","aliases":["Sông đen","Sông lớn màu đen"],"blurb":"Con sông lớn rộng mười mấy dặm nước đen dưới ngọn núi lớn, hàn khí cực mạnh khiến sinh vật như đóng băng và cắt đứt thần niệm.","detail":"Sông rộng mười mấy dặm, nước đen buốt tận linh hồn, sinh vật rơi xuống gần như bị đóng băng, thần niệm cũng bị dòng sông cắt đứt. Thạch Hạo và Tiểu Bạch nhảy xuống đây để tránh truy sát của Ngũ Sắc Khổng Tước. Tương truyền trên trời có mười ngôi sao Thái Âm, trong một trận chiến thời Thái Cổ bị chém đứt chín ngôi; một ngôi bị luyện hóa rơi vào sông này, biến nơi đây thành vùng sinh vật diệt tuyệt.","theLucLienQuan":[],"nguon":["@c0070"]},{"id":"xung-van-tran","name":"Xung Vân trấn","aliases":["Xung Vân thành"],"capDo":"thanh","parentId":"thach-quoc","blurb":"Trọng trấn biên thùy phía tây Thạch quốc, tám mươi ngàn nhân khẩu, tường thành xây bằng Kim Cương Nham đen như kim loại; có tế linh trấn giữ.","detail":"Nơi Thạch Hạo tới sau khi ra khỏi Đại Hoang; chứng kiến tế linh Xung Vân dùng xích kiếm diệt sạch thú triều.","theLucLienQuan":["Thạch Quốc","Vũ tộc"],"nguon":["@c0072"]},{"id":"tay-cuong","name":"Tây Cương","capDo":"vuc","parentId":null,"blurb":"Vùng đất nguyên thủy đáng sợ, mãnh thú và ác điểu khắp nơi, không thấy bóng người.","detail":"Được nhắc như phần đất hoang bao quanh biên thùy phía tây Thạch quốc mà Thạch Hạo đi qua trên đường tới Xung Vân trấn.","theLucLienQuan":[],"nguon":["@c0072"]},{"id":"thanh-trung-van","name":"Thành Trùng Vân","capDo":"thanh","parentId":null,"blurb":"Thành bị thú triều công, có cây Tế linh trấn thủ khiến vững như thành đồng vách sắt.","detail":"Trong thành có ngọn núi đất mọc cây Tế linh cao bốn năm trượng với ba đóa hoa như mẫu đơn to bằng cái thớt. Thú triều tụ tập tấn công, thủ lĩnh hung cầm chỉ huy nhưng bị ba phi kiếm của Tế linh chém đứt đầu. Cửa thành có người kiểm tra; người trung niên Vũ tộc mập mạp cai quản ở đây.","theLucLienQuan":["Vũ tộc"],"nguon":["@c0073"]},{"id":"to-dia-rach-nat-thach-quoc","name":"Tổ địa rách nát Thạch quốc","aliases":["Thôn trang rách nát"],"capDo":"khac","parentId":"thach-quoc","blurb":"Tổ địa cũ nát tiêu điều trong Thạch quốc, dùng làm nơi lưu đày người thân phận hiển hách phạm lỗi lớn.","detail":"Thôn trang cũ nát công trình sắp sụp đổ, xung quanh có bốn thôn và một trấn vốn để cung phụng tổ địa. Chỉ người có thân phận hiển hách trong Thạch tộc phạm lỗi lớn mới bị đày đến đây. Vị lão tổ tông cuối cùng ở đây sắp qua đời; đứa bé ‘một mình khác’ của Thạch Hạo sống cô độc tại đây, bị người hầu ngược đãi. Người trung niên Vũ tộc cảnh cáo tổ địa ‘rách nát nhưng có ý nghĩa quan trọng’.","theLucLienQuan":["Thạch Quốc"],"nguon":["@c0073"]},{"id":"dien-trang-cu-nat-tay-cuong","name":"Điền trang cũ nát","capDo":"khac","parentId":"tay-cuong","blurb":"Trang viên to lớn nhưng cũ kĩ vắng vẻ ở Tây Cương, ví như “nhà tù” nơi mấy lão nhân bị trục xuất sống ẩn.","detail":"Điền trang cũ nát ở Tây Cương là nơi mấy lão nhân từng đối tốt với gia đình Thạch Hạo bị trục xuất tới sống; kiến trúc cũ kĩ, người ở thưa thớt. Trong chương này lão nhân (anh em ruột tổ gia gia Thạch Hạo) hấp hối và qua đời tại đây, đứa cháu bệnh tật bị hai gác cổng độc ác khinh nhục. Nửa đêm Mao Cầu điều Độc Giác Nhân Hùng đập sập phòng gác cổng, nghiền nát hai chân bọn chúng.","theLucLienQuan":[],"nguon":["@c0074"]},{"id":"cu-thanh","name":"Cự Thành","cn":"","capDo":"thanh","parentId":"tay-cuong","blurb":"Tòa thành lớn ở Tây Cương, nơi có đại điện của ba vị Vương Hầu — địa điểm tra hỏi và xử tử Vũ Mông.","detail":"Cự Thành là một tòa thành lớn thuộc Tây Cương của Thạch Quốc. Trong thành có đại điện nơi ba vị Vương Hầu ngồi tra án, mỗi vị toàn thân óng ánh như một vầng thái dương, không lộ chân thân mà chỉ thấy ba đôi mắt xây bằng phù văn chứa cảnh khai thiên lập địa. Vũ Mông sau khi bị bắt được áp giải tới Cự Thành, bị quất roi vào mặt, rồi bị chém cụt hai tay, hai chân nổ tung, khai hết tội trước khi bị lôi ra chém đầu ngay tại chỗ mà không áp giải về Hoàng Đô. Đây cũng là nơi Chiến Vương bất động sau khi chém người, ra lệnh tiếp tục điều tra hướng về Vũ Vương Phủ để cảnh cáo.","theLucLienQuan":["Thạch Quốc / Thạch Tộc","Vũ Tộc"],"nguon":["@c0076"]},{"id":"chi-ton-dia-dong-phu-co","name":"Chí Tôn địa","aliases":["Động phủ Chí Tôn cái thế","Thần tàng"],"capDo":"khac","parentId":"dai-hoang","blurb":"Động phủ cổ xưa vị Chí Tôn cái thế để lại đạo thống; bị sấm sét làm lộ một góc, chứa nhiều Cốt Thư; sau chìm sâu vào lòng đất và trôi đi.","detail":"Trên mảnh đại địa này có truyền thuyết một vị Chí Tôn cái thế để lại đạo thống/truyền thừa trong một động phủ cổ xưa. Một tia sấm sét từ cửu thiên đánh xuống dãy núi làm lộ ra một góc; nhóm Thạch Vân Phong tìm được nhiều Cốt Thư nhưng không phá được cửa vào khu trung tâm. Sau đó thần tàng do sức mạnh thần bí của Cốt Văn đã chìm sâu vào lòng đất và trôi đi; Thạch Vân Phong tin nó vẫn ở khu vực này chứ không trôi xa.","theLucLienQuan":["Chí Tôn cái thế","Môn phái năm xưa của Thạch Vân Phong"],"nguon":["@c0079"]},{"id":"vung-muoi-van-dam-tu-sinh-co","name":"Vùng mười vạn dặm quanh Chí Tôn địa","capDo":"khac","parentId":"dai-hoang","blurb":"Khu vực rộng mười vạn dặm quanh Chí Tôn địa từng bị tứ đại sinh linh tàn sát, nay cỏ không mọc, sinh cơ cạn.","detail":"Phạm vi mười vạn dặm quanh Chí Tôn địa từng bị tứ đại sinh linh tàn sát trong cuộc tranh đoạt năm xưa; nay không có cỏ mọc, sinh cơ cạn kiệt. Việc hung khấu tái xuất tại đây khiến Thạch Vân Phong tin chúng có phát hiện mới về thần tàng đang chìm dưới đất.","theLucLienQuan":[],"nguon":["@c0079"]},{"id":"thon-xom-600-dam-bi-diet","name":"Thôn xóm ngoài 600 dặm","capDo":"khac","parentId":"dai-hoang","blurb":"Thôn xóm cách Thạch Thôn 600 dặm, bị hung khấu tàn sát đẫm máu toàn bộ.","detail":"Bì Hầu và Hổ Tử cưỡi Độc Giác Thú đi tra xét, phát hiện thôn xóm này đã bị tàn sát đẫm máu toàn bộ; người sống sót duy nhất thoi thóp nửa canh giờ rồi chết, kịp nói kẻ tấn công đòi cống nạp Nguyên Thủy Bảo Cốt và kim loại quý hiếm.","theLucLienQuan":["Đám hung khấu áp sát Thạch Thôn"],"nguon":["@c0079"]},{"id":"son-trai-cuop-dai-hoang","name":"Sơn trại cướp","cn":"","capDo":"khac","parentId":"dai-hoang","blurb":"Trại tạm của băng cướp lưu động trong Đại Hoang, nơi Thạch Hạo một mình xông vào diệt hậu hoạn.","detail":"Một sơn trại tạm bợ nằm ở vùng núi địa thế cao trong Đại Hoang, dựng hàng rào đơn giản, có lửa trại và mãnh thú bị trói giữ. Đây là nơi đóng quân của băng cướp lưu động do đại thủ lĩnh cai quản hơn trăm cường giả, lại nuôi giữ một con Tế Linh. Thạch Hạo cưỡi Độc Giác Thú nửa canh giờ thì tới nơi, cho Tiểu Bạch trốn rồi một mình xông vào càn quét lính gác, đánh bại thủ lĩnh giáp vảy Xuyên Sơn Giáp và giao chiến với đại thủ lĩnh cùng Tế Linh. Vùng núi quanh trại rung chuyển dữ dội khi Thái Cổ Ma Cầm và Tế Linh xuất hiện, đất đai vốn cằn cỗi.","theLucLienQuan":["Bọn cướp Đại Hoang (sơn trại đại thủ lĩnh)","Thạch Thôn"],"nguon":["@c0082"]},{"id":"vung-man-hoang-chien-truong","name":"Vùng man hoang (chiến trường núi đá)","capDo":"vuc","parentId":null,"blurb":"Khu vực núi đá cây cối vùng man hoang nơi diễn ra trận chiến sinh tử giữa nhóc tỳ và Tế Linh Xuyên Sơn Giáp.","detail":"Vùng núi đá cây cối thuộc vùng man hoang; trận chiến khiến cả vùng rung chuyển, cổ thụ gãy đổ, cự thạch tan nát, vách núi bị cương khí vàng kim đánh thủng nhiều lỗ. Đại thủ lĩnh hung khấu kinh ngạc vì một thôn nhỏ trong vùng man hoang lại xuất hiện đứa trẻ đáng sợ như nhóc tỳ.","theLucLienQuan":["Đám hung khấu vùng man hoang"],"nguon":["@c0083"]},{"id":"tieu-tay-thien-vung","name":"Tiểu Tây Thiên","cn":"","capDo":"khac","parentId":null,"blurb":"Thế giới/vùng thần bí, nơi xuất thân của Tế Linh lai lịch lớn.","detail":"Vùng thần bí gợi liên hệ ý cực lạc; là nơi xuất thân của con Tế Linh (Xuyên Sơn Giáp) từng tới Đại Hoang. Sau khi Tế Linh bị diệt, Tiểu Tây Thiên vẫn chưa có phản ứng.","theLucLienQuan":["Tiểu Tây Thiên"],"nguon":["@c0086"]},{"id":"hu-than-gioi","name":"Hư Thần Giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Thế giới tinh thần cổ xưa, nơi rèn luyện tinh thần rồi mang cảm ngộ về chân thân.","detail":"Thế giới tinh thần cổ xưa, tương truyền do Thần Linh được Tiên dân Thượng Cổ thờ phụng cùng dùng cảm giác tinh thần xây dựng nên (có cách nói là thế giới tiến vào sau khi thành thần). Sau một biến động thời Thượng Cổ, thế giới rách nát sinh ra nhiều phế tích với cung điện đổ nát, thần sơn gãy rời. Người tu đưa ý chí tinh thần vào đây rèn luyện như tái sinh; cảm ngộ đạt được sẽ mang về thân thể thật như chân thân tu hành. Thế giới hùng vĩ vô biên, có nhiều sinh linh ngoại giới cùng đưa tinh thần vào đông như một quốc gia.","theLucLienQuan":["Quốc gia cổ","Thạch thôn"],"nguon":["@c0087"]},{"id":"so-thuy-dia","name":"Sơ Thủy Địa","cn":"","capDo":"vuc","parentId":"hu-than-gioi","blurb":"Khu vực người mới tới Hư Thần Giới nhất định bị đưa vào.","detail":"Khu vực khởi đầu mà mọi người mới tới Hư Thần Giới nhất định bị đưa vào, đầy phế tích và các tảng đá lóe Phù Văn khảm Nguyên Thủy Bảo Cốt cùng thông đạo phù văn. Tu hành viên mãn tại đây mới được dùng thông đạo lên khu vực cấp cao hơn. Nhóc tỳ xuất hiện ở đây và ngây ngô đào Bảo Cốt, phá hỏng thông đạo.","theLucLienQuan":[],"nguon":["@c0087"]},{"id":"dong-thien-phuc-dia-hu-than-gioi","name":"Động Thiên Phúc Địa","cn":"","capDo":"vuc","parentId":"hu-than-gioi","blurb":"Khu vực cao tầng của Hư Thần Giới, đối lập với Sơ Thủy Địa.","detail":"Khu vực cấp cao hơn trong Hư Thần Giới, được nhắc để phân cấp so với Sơ Thủy Địa; chỉ đến được sau khi tu hành viên mãn và dùng thông đạo phù văn dịch chuyển lên.","theLucLienQuan":[],"nguon":["@c0087"]},{"id":"dong-tien-tang-cao-hu-than-gioi","name":"Động tiên tầng cao Hư Thần Giới","capDo":"khac","parentId":"hu-than-gioi","blurb":"Các lĩnh vực tầng cao hơn Sơ Thủy Địa trong Hư Thần Giới; thông đạo kiên cố hơn nhiều, cũng có bia đá nổi lên báo kỷ lục.","detail":"Bên trên Sơ Thủy Địa, Hư Thần Giới còn nhiều tầng động tiên khác. Thông đạo ở đây kiên cố hơn hẳn tầng thấp, khi có kỷ lục Sơ Thủy Địa được lập, bia đá cũng nổi lên khắp các tầng cao báo tin. Theo suy đoán, Thần Nhân Thượng Cổ có thể còn cư ngụ ở những động tiên tầng cao hơn nữa.","theLucLienQuan":["Hư Thần Giới"],"nguon":["@c0089"]},{"id":"phieu-mieu-dong-thien","name":"Phiêu Miểu động thiên","capDo":"khac","parentId":"hu-than-gioi","blurb":"Một động thiên nơi có tu sĩ đang tu hành, được nhắc trong lời hàn huyên ở Sơ Thủy Địa.","detail":"Được nhắc thoáng qua khi tu sĩ nói với nhau về Thương Hải đạo hữu đã đi trước.","theLucLienQuan":[],"nguon":["@c0092"]},{"id":"dong-thien-tang-cao-tu-dai-gia-toc","name":"Động thiên tầng cao (tứ đại gia tộc)","capDo":"khac","parentId":"hu-than-gioi","blurb":"Tầng cao Hư Thần Giới nơi cường giả bốn đại tộc thủ hộ.","detail":"Các cao thủ răng tóc rụng hết thường trú tại đây, đọc bia kỷ lục Hư Thần Giới rồi xuống Sơ Thủy Địa xem náo nhiệt về Thạch Hạo.","theLucLienQuan":["Tứ đại gia tộc"],"nguon":["@c0092"]},{"id":"ngon-nui-ky-luc-thach-nghi","name":"Ngọn núi giữ kỷ lục Thạch Nghị","capDo":"khac","parentId":"hu-than-gioi","blurb":"Ngọn núi cách Sơ Thủy Địa mấy dặm, nơi lưu kỷ lục đáng sợ của Thạch Nghị chưa ai phá.","detail":"Tinh Bích đại gia báo tin đã tìm được ngọn núi này; nhiều thiên tài từng đến phá kỷ lục đều thất bại, lòng tin bị đả kích. Thạch Hạo tuyên bố sẽ đi phá.","theLucLienQuan":[],"nguon":["@c0092"]},{"id":"song-tu-son","name":"Song Tử Sơn","capDo":"khac","parentId":"so-thuy-dia","blurb":"Cặp núi trong Sơ Thủy Địa, tòa bên cạnh cao hơn mấy trượng; phía trước có hồ xanh biếc, phía sau có thác trắng xóa. Nơi giữ kỷ lục nhảy thân thể của Thạch Nghị và bị Nhóc tỳ phá vượt.","detail":"Khu sơn địa khí thế phi phàm, có nhiều mãnh thú hung cầm sinh sống. Năm xưa Thạch Nghị giậm chân xông thẳng lên đặt chân lên đỉnh trước mặt nhiều tộc chủ đại tộc, tạo kỷ lục hai năm chưa ai phá; Nhóc tỳ chọn tòa cao hơn để tái lập và phá vượt.","theLucLienQuan":["Thạch Quốc","Vũ Tộc","Bổ Thiên các","Trục Lộc thư viện"],"nguon":["@c0093"]},{"id":"phe-tich-lieu-than","name":"Phế tích (nơi Liễu thần cắm rễ)","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng tường đổ cổ kính ngoài Sơ Thủy Địa, có Liễu thần chọc trời và tảng đá xanh làm thông đạo.","detail":"Phế tích nằm ngoài Sơ Thủy Địa gần Thái Cổ Ma sơn, có cây liễu thần cắm rễ và tảng đá xanh lớn nối thông đạo về Sơ Thủy Địa. Nhóc tỳ xuất hiện tại đây sau khi bị trục xuất.","theLucLienQuan":[],"nguon":["@c0095"]},{"id":"thach-quoc","name":"Thạch quốc","cn":"石国","capDo":"quoc-gia","parentId":null,"blurb":"Quốc gia nằm ở biên cương Đại Hoang, nơi hai nhóc tới sau hơn nửa năm vượt 300.000 dặm.","detail":"Thạch Hạo và Thanh Phong tới biên cương Thạch quốc sau hơn nửa năm vượt Đại Hoang, vào qua một thành trì khác con đường lần trước.","theLucLienQuan":[],"nguon":["@c0095"]},{"id":"bo-thien-cac-vung","name":"Bổ Thiên Các","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng tịnh thổ cổ xưa, đích đến của nhóc tỳ và mọi thế lực; cách Trục Lộc Thư Viện chín vạn dặm.","detail":"Bổ Thiên Các là vùng tịnh thổ tu hành cổ xưa, đích đến của nhóc tỳ và vô số thế lực. Gần đây cực kỳ náo nhiệt vì tin nhóc tỳ sắp tới; cách Trục Lộc Thư Viện chín vạn dặm. Nơi đây sắp mở Thánh Viện.","theLucLienQuan":["Bổ Thiên Các"],"nguon":["@c0096"]},{"id":"truc-loc-thu-vien","name":"Trục Lộc Thư Viện","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng tịnh thổ cùng hướng với Bổ Thiên Các, cách nhau chín vạn dặm.","detail":"Trục Lộc Thư Viện là vùng tịnh thổ tu hành cùng hướng với Bổ Thiên Các, cách nhau chín vạn dặm; cũng là một trong hai nơi các thế lực chờ đón nhóc tỳ.","theLucLienQuan":[],"nguon":["@c0096"]},{"id":"thanh-vien","name":"Thánh Viện","cn":"","capDo":"khac","parentId":"bo-thien-cac-vung","blurb":"Nơi Bổ Thiên Các sắp mở, chỉ nhân kiệt ưu tú nhất mới được vào.","detail":"Thánh Viện là nơi Bổ Thiên Các tuyên bố sắp mở, chỉ nhân kiệt ưu tú nhất mới được đi vào; tin này khiến phong vân tụ hội, và là mục tiêu Thạch Nghị muốn vào xem.","theLucLienQuan":["Bổ Thiên Các"],"nguon":["@c0096"]},{"id":"ban-huyet-canh","name":"Bàn Huyết Cảnh","cn":"","capDo":"khac","parentId":null,"blurb":"Cảnh giới/vùng hạn chế mà mấy lão bán tin bị giới hạn.","detail":"Bàn Huyết Cảnh là cảnh giới/vùng hạn chế mà Chùy thúc, Điểu gia và mấy lão bị giới hạn, khiến họ ngại đối đầu nhóc tỳ.","theLucLienQuan":[],"nguon":["@c0096"]},{"id":"nguyen-thuy-chien-truong","name":"Nguyên Thủy chiến trường","cn":"","capDo":"khac","parentId":"bo-thien-cac-vung","blurb":"Vùng phía tây Bổ Thiên các, nguyên là chiến trường thượng cổ, nay hoang vắng, do Bổ Thiên các quản lý làm nơi thí luyện.","detail":"Rộng lớn, đầy chướng khí, chia làm tám khu vực bố trí Phù Văn trận vực để sàng lọc thí sinh vượt ải. Dưới lòng đất chôn nhiều Nguyên Thủy Bảo Cốt gắn với các bố trí Phù Văn. Xuyên thủng trận vực có thể vào chiến trường tầng hai, nơi có nhiều hung thú dành cho thiên tài.","theLucLienQuan":["Bổ Thiên các"],"nguon":["@c0098"]},{"id":"chien-truong-tang-hai","name":"Chiến trường tầng hai","cn":"","capDo":"khac","parentId":"nguyen-thuy-chien-truong","blurb":"Tầng sâu hơn của Nguyên Thủy chiến trường, có nhiều hung thú, dành cho thiên tài rèn luyện.","detail":"Chỉ những thí sinh xuyên thủng được Phù Văn trận vực ở tầng ngoài mới có tư cách vào; hung thú dày đặc, là nơi thiên tài rèn luyện và cửa ải cuối cùng đầy nguy cơ toàn quân bị diệt.","theLucLienQuan":["Bổ Thiên các"],"nguon":["@c0098"]},{"id":"chien-truong-thu-hai","name":"Chiến trường thứ hai","capDo":"khac","parentId":"bo-thien-cac-vung","blurb":"Khu rừng rậm núi non đầy hung thú nơi thiên tài tranh Bổ Thiên Thạch, thuộc hậu viện Bổ Thiên các.","detail":"Khu rừng rậm núi non đầy hung thú của hậu viện Bổ Thiên các, không có quy tắc, tỉ lệ chết chóc cao; nơi các thiên tài tranh đoạt Bổ Thiên Thạch. Có đầm lầy, thác nước với Cổ Ngạc và giao thú hung linh, cùng sào huyệt Hắc Hổ ở nơi sâu nhất.","theLucLienQuan":["Bổ Thiên các"],"nguon":["@c0100"]},{"id":"sao-huyet-hac-ho","name":"Sào huyệt Hắc Hổ","capDo":"khac","parentId":"chien-truong-thu-hai","blurb":"Cao điểm không cây cỏ đầy sát khí và sương mù đen, cấm địa của hung thú siêu cấp.","detail":"Cao điểm không cây cỏ, đầy sát khí và sương mù màu đen, mặt đất khô rắn như nham thạch; có một cái hang lớn đen ngòm tỏa hắc sát, là cấm địa của hung thú siêu cấp. Ở miệng hang mọc cây Hắc Sát Liên hấp thu sát khí của Hắc Hổ.","nguon":["@c0100"]},{"id":"thuong-co-tinh-tho","name":"Thượng Cổ Tịnh Thổ","capDo":"vuc","parentId":null,"blurb":"Mảnh linh thổ phồn thịnh an lành nơi có Bổ Thiên các.","detail":"Mảnh linh thổ phồn thịnh an lành, linh khí nồng nặc, có hồ nước linh ngư và Thụy Thú ẩn hiện. Là nơi tọa lạc của Bổ Thiên các, các bộ lạc lớn và siêu cấp cự tộc vượt hàng chục đến trăm vạn dặm qua Đại Hoang đưa hài tử tới dự tuyển đệ tử.","theLucLienQuan":["Bổ Thiên các"],"nguon":["@c0097"]},{"id":"son-mon-bo-thien-cac","name":"Sơn môn Bổ Thiên các","capDo":"khac","parentId":"thuong-co-tinh-tho","blurb":"Hai toà núi đá đặt ngang thành cửa thiên nhiên nguy nga, phía ngoài có bia đá khắc ba chữ Bổ Thiên Các.","detail":"Cửa vào sơn môn thật của Bổ Thiên các, gồm hai toà núi đá đặt ngang thành cửa thiên nhiên nguy nga; lão nhân tiên phong đạo cốt ngồi trên tảng đá xanh canh giữ. Phía ngoài trăm dặm có tấm bia lớn khắc ba chữ Bổ Thiên Các, khu vực bên ngoài trồng Linh Dược không ai dám trộm.","theLucLienQuan":["Bổ Thiên các"],"nguon":["@c0097"]}]};
